<?php

// Generated by make_tool. Do not edit by hand unless you know why.

$toolDefinition_structured_data_scraper = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'structured_data_scraper',
    'description' => 'Fetch an HTML page, extract structured tabular data using DOMDocument/DOMXPath: finds all HTML tables and extracts headers+rows, detects JSON-LD script tags, looks for microdata/ RDFa, and persists everything to SQLite with schema auto-detection. Returns a report of what was found and stored. Combines HTML parsing (DOM), structured extraction (XPath), and persistent storage (SQLite) in one pipeline. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'url' => 
        array (
          'type' => 'string',
          'description' => 'The URL to scrape for structured data.',
        ),
        'db_name' => 
        array (
          'type' => 'string',
          'description' => 'SQLite database filename (stored in workspace). Default: \'scraped_data.sqlite\'.',
        ),
        'timeout' => 
        array (
          'type' => 'integer',
          'description' => 'HTTP timeout in seconds (5-30, default: 20).',
        ),
        'max_tables' => 
        array (
          'type' => 'integer',
          'description' => 'Maximum HTML tables to extract (1-20, default: 10).',
        ),
        'max_records_per_table' => 
        array (
          'type' => 'integer',
          'description' => 'Maximum rows per table (0=all, default: 100).',
        ),
        'extract_jsonld' => 
        array (
          'type' => 'boolean',
          'description' => 'If true, also extract JSON-LD structured data from script tags. Default: true.',
        ),
      ),
      'required' => 
      array (
        0 => 'url',
      ),
    ),
  ),
);

if (! function_exists('structured_data_scraper')) {
    function structured_data_scraper($url, $db_name = null, $timeout = null, $max_tables = null, $max_records_per_table = null, $extract_jsonld = null)
    {
        // Structured Data Scraper — extract HTML tables + JSON-LD + microdata to SQLite
        $url = $url ?? '';
        $db_name = $db_name ?? 'scraped_data.sqlite';
        $timeout = $timeout ?? 20;
        $max_tables = $max_tables ?? 10;
        $max_records_per_table = $max_records_per_table ?? 100;
        $extract_jsonld = $extract_jsonld ?? true;

        if (empty($url)) return ['error' => 'URL is required', 'success' => false];
        if (!preg_match('#^https?://#i', $url)) return ['error' => 'URL must start with http:// or https://', 'success' => false];
        $timeout = max(5, min(30, (int)$timeout));
        $max_tables = max(1, min(20, (int)$max_tables));
        $max_records_per_table = max(0, min(500, (int)$max_records_per_table));

        $workspace = __DIR__ . '/../workspace';
        $db_path = $workspace . '/' . basename($db_name);
        $db_dir = dirname($db_path);
        if (!is_dir($db_dir)) @mkdir($db_dir, 0777, true);

        try {
            $pdo = new PDO("sqlite:$db_path");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
        } catch (Exception $e) {
            return ['error' => 'DB init: ' . $e->getMessage(), 'success' => false];
        }

        // Fetch the page
        $ctx = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: structured_data_scraper/1.0\r\nAccept: text/html\r\n",
                'ignore_errors' => true,
                'follow_location' => 1,
                'max_redirects' => 3,
            ],
            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
        ]);

        $start = microtime(true);
        $html = @file_get_contents($url, false, $ctx);
        $fetch_ms = round((microtime(true) - $start) * 1000);

        if ($html === false) {
            return ['error' => 'Fetch failed: ' . (error_get_last()['message'] ?? 'unknown'), 'success' => false];
        }

        $status_code = 200;
        if (isset($http_response_header)) {
            foreach ($http_response_header as $h) {
                if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status_code = (int)$m[1]; break; }
            }
        }
        if ($status_code >= 400) return ['error' => "HTTP $status_code", 'success' => false];

        libxml_use_internal_errors(true);
        $dom = new DOMDocument();
        @$dom->loadHTML('<?xml encoding="UTF-8">' . $html);
        libxml_clear_errors();
        $xpath = new DOMXPath($dom);

        $page_title = '';
        $tn = $xpath->query('//title');
        if ($tn && $tn->length > 0) $page_title = trim($tn->item(0)->textContent);

        $results = [];
        $tables_found = 0;
        $tables_stored = 0;
        $jsonld_found = 0;

        // ============ 1. HTML Tables ============
        $table_nodes = $xpath->query('//table');
        $tables_found = $table_nodes->length;

        $table_count = 0;
        foreach ($table_nodes as $table_node) {
            if ($table_count >= $max_tables) break;
            $table_count++;
            
            $table_name = 'table_' . $table_count;
            $caption_nodes = $xpath->query('.//caption', $table_node);
            if ($caption_nodes && $caption_nodes->length > 0) {
                $table_name = preg_replace('/[^a-zA-Z0-9_]/', '_', trim($caption_nodes->item(0)->textContent));
                $table_name = mb_substr($table_name, 0, 50);
            } else {
                $prev = $table_node->previousSibling;
                while ($prev) {
                    if (in_array($prev->nodeName, ['h1','h2','h3','h4'])) {
                        $table_name = preg_replace('/[^a-zA-Z0-9_]/', '_', trim($prev->textContent));
                        $table_name = mb_substr($table_name, 0, 50);
                        break;
                    }
                    $prev = $prev->previousSibling;
                }
            }
            $table_name = ltrim($table_name, '0123456789');
            if (empty($table_name)) $table_name = 'table_' . $table_count;
            
            // Extract headers
            $headers = [];
            $header_nodes = $xpath->query('.//thead//th | .//tr[1]//th', $table_node);
            if ($header_nodes->length === 0) {
                $first_row = $xpath->query('.//tr[1]/td', $table_node);
                if ($first_row->length > 0) {
                    foreach ($first_row as $td) {
                        $headers[] = trim(preg_replace('/\s+/', ' ', $td->textContent));
                    }
                }
            } else {
                foreach ($header_nodes as $th) {
                    $headers[] = trim(preg_replace('/\s+/', ' ', $th->textContent));
                }
            }
            
            $clean_headers = [];
            $ci = 0;
            foreach ($headers as $h) {
                $ci++;
                $clean = preg_replace('/[^a-zA-Z0-9_]/', '_', $h);
                $clean = trim($clean, '_');
                if (empty($clean)) $clean = 'col_' . $ci;
                $clean_headers[] = $clean;
            }
            
            if (empty($clean_headers)) {
                $fc = $xpath->query('.//tr[1]/td', $table_node);
                for ($i = 1; $i <= max(1, $fc->length); $i++) {
                    $clean_headers[] = 'col_' . $i;
                }
            }
            
            // Extract data rows
            $rows = [];
            $row_nodes = $xpath->query('.//tr', $table_node);
            $skip = ($header_nodes->length === 0);
            
            foreach ($row_nodes as $row_node) {
                if ($skip) { $skip = false; continue; }
                
                $cells = $xpath->query('.//td', $row_node);
                if ($cells->length === 0) continue;
                
                $row_data = [];
                foreach ($cells as $i => $td) {
                    $val = trim(preg_replace('/\s+/', ' ', strip_tags($td->ownerDocument->saveHTML($td))));
                    // strip_tags the td html to get cleaner text
                    $val = trim(strip_tags($val));
                    $cn = $clean_headers[$i] ?? 'col_' . ($i + 1);
                    $row_data[$cn] = $val;
                }
                $rows[] = $row_data;
            }
            
            if (empty($rows)) continue;
            
            if ($max_records_per_table > 0 && count($rows) > $max_records_per_table) {
                $rows = array_slice($rows, 0, $max_records_per_table);
            }
            
            // Auto-detect types
            $col_types = [];
            foreach ($clean_headers as $h) {
                $col_types[$h] = 'TEXT';
                $all_int = true;
                $all_num = true;
                $sc = min(20, count($rows));
                for ($i = 0; $i < $sc; $i++) {
                    if (!isset($rows[$i][$h])) continue;
                    $v = $rows[$i][$h];
                    if (!ctype_digit(ltrim($v, '- '))) $all_int = false;
                    if (!is_numeric($v)) $all_num = false;
                }
                if ($all_int) $col_types[$h] = 'INTEGER';
                elseif ($all_num) $col_types[$h] = 'REAL';
            }
            
            $safe_name = preg_replace('/[^a-zA-Z0-9_]/', '_', $table_name);
            $safe_name = mb_substr($safe_name, 0, 60);
            if (empty($safe_name)) $safe_name = 'table_' . $table_count;
            
            $col_defs = [];
            foreach ($clean_headers as $h) {
                $col_defs[] = '"' . $h . '" ' . $col_types[$h];
            }
            
            try {
                $pdo->exec('DROP TABLE IF EXISTS "' . $safe_name . '"');
                $pdo->exec('CREATE TABLE "' . $safe_name . '" (id INTEGER PRIMARY KEY AUTOINCREMENT, ' . implode(', ', $col_defs) . ')');
                
                $ph = implode(', ', array_fill(0, count($clean_headers), '?'));
                $ins = $pdo->prepare('INSERT INTO "' . $safe_name . '" ("' . implode('", "', $clean_headers) . '") VALUES (' . $ph . ')');
                
                $inserted = 0;
                foreach ($rows as $row) {
                    $vals = [];
                    foreach ($clean_headers as $h) {
                        $vals[] = $row[$h] ?? null;
                    }
                    try { $ins->execute($vals); $inserted++; } catch (Exception $e) {}
                }
                
                $cnt = $pdo->query("SELECT COUNT(*) as c FROM \"$safe_name\"")->fetch(PDO::FETCH_ASSOC)['c'];
                
                $results[] = [
                    'type' => 'html_table',
                    'name' => $safe_name,
                    'columns' => count($clean_headers),
                    'rows' => (int)$cnt,
                    'schema' => $col_types,
                ];
                $tables_stored++;
            } catch (Exception $e) {
                $results[] = ['type' => 'html_table', 'name' => $safe_name, 'error' => $e->getMessage()];
            }
        }

        // ============ 2. JSON-LD ============
        if ($extract_jsonld) {
            $ld_nodes = $xpath->query('//script[@type="application/ld+json"]');
            $jsonld_found = $ld_nodes->length;
            
            $ld_count = 0;
            foreach ($ld_nodes as $node) {
                $ld_count++;
                $json_raw = trim($node->textContent);
                $decoded = @json_decode($json_raw, true);
                if ($decoded === null) continue;
                
                // Handle both single object and @graph arrays
                $items = isset($decoded['@graph']) ? $decoded['@graph'] : [$decoded];
                
                foreach ($items as $item) {
                    if (!is_array($item)) continue;
                    
                    $type = $item['@type'] ?? 'Thing';
                    $tbl = preg_replace('/[^a-zA-Z0-9_]/', '_', $type);
                    if (empty($tbl)) $tbl = 'jsonld_' . $ld_count;
                    
                    $flat = [];
                    foreach ($item as $k => $v) {
                        if ($k === '@context' || $k === '@type') continue;
                        if (is_scalar($v)) {
                            $sk = preg_replace('/[^a-zA-Z0-9_]/', '_', $k);
                            $flat[$sk] = is_bool($v) ? ($v ? '1' : '0') : (string)$v;
                        } elseif (is_array($v) && isset($v[0]) && is_scalar($v[0])) {
                            $sk = preg_replace('/[^a-zA-Z0-9_]/', '_', $k);
                            $flat[$sk] = implode(', ', $v);
                        }
                    }
                    
                    if (empty($flat)) continue;
                    
                    try {
                        $pdo->exec('CREATE TABLE IF NOT EXISTS "' . $tbl . '" (id INTEGER PRIMARY KEY AUTOINCREMENT, ' . implode(', ', array_map(fn($c) => "\"$c\" TEXT", array_keys($flat))) . ')');
                        $cols = array_keys($flat);
                        $ph = implode(', ', array_fill(0, count($cols), '?'));
                        $ins = $pdo->prepare('INSERT INTO "' . $tbl . '" ("' . implode('", "', $cols) . '") VALUES (' . $ph . ')');
                        $ins->execute(array_values($flat));
                        
                        $results[] = [
                            'type' => 'jsonld',
                            'name' => $tbl,
                            'context' => $item['@context'] ?? 'N/A',
                            'schema_type' => $item['@type'] ?? 'N/A',
                            'properties' => count($flat),
                        ];
                    } catch (Exception $e) {}
                }
            }
        }

        // ============ 3. Microdata ============
        $microdata_found = 0;
        $md_count = 0;
        $scope_nodes = $xpath->query('//*[@itemscope]');
        $microdata_found = $scope_nodes->length;

        foreach ($scope_nodes as $node) {
            if ($md_count >= 5) break;
            $md_count++;
            
            $itemtype = $node->getAttribute('itemtype') ?: 'Thing';
            $itemtype = preg_replace('#^https?://schema\.org/#', '', $itemtype);
            
            $props = [];
            $pnodes = $xpath->query('.//*[@itemprop]', $node);
            foreach ($pnodes as $pn) {
                $name = $pn->getAttribute('itemprop');
                $val = '';
                if ($pn->hasAttribute('content')) $val = $pn->getAttribute('content');
                elseif ($pn->nodeName === 'meta') $val = $pn->getAttribute('content') ?: $pn->getAttribute('value');
                elseif ($pn->nodeName === 'a' || $pn->nodeName === 'link') $val = $pn->getAttribute('href') ?: trim($pn->textContent);
                elseif ($pn->nodeName === 'img') $val = $pn->getAttribute('src') ?: $pn->getAttribute('alt');
                elseif ($pn->nodeName === 'time') $val = $pn->getAttribute('datetime') ?: trim($pn->textContent);
                else $val = trim($pn->textContent);
                $props[$name] = mb_substr($val, 0, 500);
            }
            
            if (empty($props)) continue;
            
            $md_name = preg_replace('/[^a-zA-Z0-9_]/', '_', $itemtype) . '_md';
            if (empty($md_name) || $md_name === '_md') $md_name = 'microdata_' . $md_count;
            
            try {
                $pdo->exec('CREATE TABLE IF NOT EXISTS "' . $md_name . '" (id INTEGER PRIMARY KEY AUTOINCREMENT, ' . implode(', ', array_map(fn($c) => "\"$c\" TEXT", array_keys($props))) . ')');
                $cols = array_keys($props);
                $ph = implode(', ', array_fill(0, count($cols), '?'));
                $ins = $pdo->prepare('INSERT INTO "' . $md_name . '" ("' . implode('", "', $cols) . '") VALUES (' . $ph . ')');
                $ins->execute(array_values($props));
                
                $results[] = ['type' => 'microdata', 'name' => $md_name, 'schema_type' => $itemtype, 'properties' => count($props)];
            } catch (Exception $e) {}
        }

        $all_tables = $pdo->query("SELECT name FROM sqlite_master WHERE type='table'")->fetchAll(PDO::FETCH_COLUMN);

        return [
            'success' => true,
            'url' => $url,
            'page_title' => $page_title,
            'fetch_time_ms' => $fetch_ms,
            'html_size_bytes' => strlen($html),
            'tables_found_in_html' => $tables_found,
            'tables_extracted' => $table_count,
            'tables_stored' => $tables_stored,
            'jsonld_found' => $jsonld_found,
            'microdata_found' => $microdata_found,
            'total_tables_in_db' => count($all_tables),
            'details' => $results,
            'tables_in_database' => $all_tables,
            'database' => $db_name,
            'query_hint' => 'sqlite_query db_name="' . $db_name . '" sql="SELECT * FROM [table_name]"',
        ];
    }
}
